            value={summary?.balance || 0}
            change={summary?.balanceChange}
            icon={<Wallet className="h-5 w-5" />}
            variant="balance"
            isLoading={isLoading}
          />
          <StatsCard
            title="Transactions"
            value={summary?.transactionCount || 0}
            icon={<DollarSign className="h-5 w-5" />}
            isCurrency={false}
