import { useTheme, useNotification } from '@/contexts';
import { SUPPORTED_CURRENCIES, DATE_FORMAT_OPTIONS } from '@/utils/constants';
import { cn } from '@/utils/helpers';

type ThemeOption = 'light' | 'dark' | 'system';

const themeOptions: { value: ThemeOption; label: string; icon: typeof Sun }[] = [
  { value: 'light', label: 'Light', icon: Sun },
  { value: 'dark', label: 'Dark', icon: Moon },
  { value: 'system', label: 'System', icon: Monitor },
];

export function Settings() {
  const { theme, setTheme } = useTheme();
  const { success } = useNotification();

  const [preferences, setPreferences] = useState({
    currency: 'USD',
    dateFormat: 'MM/dd/yyyy',
    startOfWeek: 'monday',
    emailNotifications: true,
    pushNotifications: true,
    budgetAlerts: true,
    weeklyReport: false,
    monthlyReport: true,
  });

  const handlePreferenceChange = (key: string, value: string | boolean) => {
    setPreferences((prev) => ({ ...prev, [key]: value }));
    success('Settings saved');
  };

  const handleExportData = () => {
    success('Data export started', 'You will receive an email when ready');
  };

  const handleClearData = () => {
    success('Data cleared successfully');
  };

  return (
    <MainLayout>
      <div className="mx-auto max-w-2xl space-y-6">
        <div>
          <h1 className="text-2xl font-bold">Settings</h1>
          <p className="text-muted-foreground">Customize your experience</p>
        </div>

        {/* Appearance */}
        <Card>
          <CardHeader>
            <CardTitle>Appearance</CardTitle>
            <CardDescription>Customize how the app looks</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div>
              <label className="mb-2 block text-sm font-medium">Theme</label>
              <div className="grid grid-cols-3 gap-3">
                {themeOptions.map((option) => {
                  const Icon = option.icon;
                  return (
                    <button
                      key={option.value}
                      onClick={() => setTheme(option.value)}
                      className={cn(
                        'flex flex-col items-center gap-2 rounded-lg border p-4 transition-colors',
                        theme === option.value
                          ? 'border-primary bg-primary/5'
                          : 'border-border hover:bg-muted'
                      )}
                    >
                      <Icon className="h-5 w-5" />
                      <span className="text-sm font-medium">{option.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Preferences */}
        <Card>
          <CardHeader>
            <CardTitle>Preferences</CardTitle>
            <CardDescription>Set your default preferences</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <Select
              label="Currency"
              options={SUPPORTED_CURRENCIES}
              value={preferences.currency}
              onChange={(e) => handlePreferenceChange('currency', e.target.value)}
            />

